/**
 * File Name: i18n-core.ts — v1.0.0
 * Description: Core desacoplado do sistema i18n do BTS Utilities.
 *              ES module — sem UMD, sem dependência de runtime externo.
 * Author: Jeferson Padilha (https://jepasa.com)
 */
import { DEFAULT_LOCALE, GLOBAL_KEY } from './i18n-conf.js';
// ─── Helpers ──────────────────────────────────────────────────────────────────
function normalizeString(value) {
    return String(value ?? '').trim();
}
function normalizeLocaleInput(locale) {
    return normalizeString(locale).replace(/_/g, '-');
}
function normalizeLocaleToken(locale) {
    return normalizeLocaleInput(locale).toLowerCase();
}
function toCanonicalLocale(locale) {
    const normalized = normalizeLocaleInput(locale);
    if (!normalized)
        return '';
    const parts = normalized.split('-').filter(Boolean);
    if (parts.length === 0)
        return '';
    return parts
        .map((part, index) => {
        if (index === 0)
            return part.toLowerCase();
        if (part.length === 2)
            return part.toUpperCase();
        if (part.length === 4)
            return part.charAt(0).toUpperCase() + part.slice(1).toLowerCase();
        return part.toLowerCase();
    })
        .join('-');
}
function getShortPart(locale) {
    return locale ? normalizeLocaleInput(locale).split('-')[0] : '';
}
function getLocaleFromHtmlLang() {
    if (typeof document === 'undefined')
        return '';
    const lang = document.documentElement.getAttribute('lang');
    return normalizeString(lang);
}
function getLocaleFromNavigator() {
    if (typeof navigator === 'undefined')
        return '';
    const langs = Array.isArray(navigator.languages) ? navigator.languages : [];
    const candidate = langs[0] ?? navigator.language;
    return normalizeString(candidate);
}
function resolveExactLocale(locale, dicts) {
    if (!locale)
        return '';
    const direct = normalizeString(locale);
    if (direct && dicts[direct])
        return direct;
    const canonical = toCanonicalLocale(locale);
    if (canonical && dicts[canonical])
        return canonical;
    const token = normalizeLocaleToken(locale);
    if (!token)
        return '';
    const equivalent = Object.keys(dicts).find((key) => normalizeLocaleToken(key) === token);
    return equivalent ?? '';
}
function resolvePreferredDefaults(dicts) {
    if (dicts['en-US'])
        return 'en-US';
    return '';
}
function resolveFirstAvailableLocale(dicts) {
    const keys = Object.keys(dicts);
    return keys.length ? keys[0] : '';
}
function getByPath(obj, path) {
    return String(path)
        .split('.')
        .filter(Boolean)
        .reduce((acc, part) => {
        if (acc !== null && acc !== undefined && typeof acc === 'object') {
            return acc[part];
        }
        return undefined;
    }, obj);
}
// ─── Factory ──────────────────────────────────────────────────────────────────
export function createManager(options = {}) {
    const defaultLocale = toCanonicalLocale(options.defaultLocale ?? DEFAULT_LOCALE) || DEFAULT_LOCALE;
    const globalKey = normalizeString(options.globalKey ?? GLOBAL_KEY);
    const rootRef = options.rootRef ?? null;
    const shortToCanonical = Object.fromEntries(Object.entries(options.shortToCanonical ?? {}).map(([short, canonical]) => [
        normalizeLocaleToken(short).split('-')[0],
        toCanonicalLocale(canonical) || normalizeLocaleInput(canonical),
    ]));
    const dictionaries = { ...(options.dictionaries ?? {}) };
    // Garante entrada para o defaultLocale
    if (!dictionaries[defaultLocale])
        dictionaries[defaultLocale] = {};
    // Mescla dicionários globais injetados externamente (ex.: via <script>)
    if (rootRef) {
        const globalDictionaries = rootRef[globalKey];
        if (globalDictionaries && typeof globalDictionaries === 'object') {
            Object.entries(globalDictionaries).forEach(([locale, strings]) => {
                dictionaries[locale] = strings;
            });
        }
    }
    function resolveShort(localeCode) {
        if (!localeCode)
            return '';
        const short = normalizeLocaleToken(localeCode).split('-')[0];
        if (!short)
            return '';
        const direct = resolveExactLocale(short, dictionaries);
        if (direct)
            return direct;
        const byKeyShort = Object.keys(dictionaries).find((key) => getShortPart(key).toLowerCase() === short);
        if (byKeyShort)
            return byKeyShort;
        const mapped = shortToCanonical[short];
        return mapped ? resolveExactLocale(mapped, dictionaries) : '';
    }
    function normalizeLocale(locale, fallback) {
        const fallbackLocale = toCanonicalLocale(fallback ?? defaultLocale) || defaultLocale;
        const normalized = toCanonicalLocale(locale) || normalizeLocaleInput(locale);
        return (resolveExactLocale(normalized, dictionaries) ||
            resolveShort(getShortPart(normalized)) ||
            resolveExactLocale(fallbackLocale, dictionaries) ||
            resolveShort(getShortPart(fallbackLocale)) ||
            resolvePreferredDefaults(dictionaries) ||
            resolveFirstAvailableLocale(dictionaries) ||
            'en-US');
    }
    function getLocaleFromEnvironment() {
        return getLocaleFromHtmlLang() || getLocaleFromNavigator() || '';
    }
    function getLocaleFromDocument() {
        return normalizeLocale(getLocaleFromEnvironment(), defaultLocale);
    }
    function getStrings(locale) {
        const resolved = normalizeLocale(locale, defaultLocale);
        return dictionaries[resolved] ?? dictionaries[defaultLocale] ?? {};
    }
    function registerLocale(locale, strings) {
        if (!locale || typeof strings !== 'object')
            return;
        const normalized = toCanonicalLocale(locale) || normalizeLocaleInput(locale);
        if (!normalized)
            return;
        dictionaries[normalized] = strings;
        const short = getShortPart(normalized).toLowerCase();
        if (shortToCanonical[short] === undefined)
            shortToCanonical[short] = normalized;
        if (rootRef) {
            let globalDicts = rootRef[globalKey];
            if (!globalDicts) {
                globalDicts = {};
                rootRef[globalKey] = globalDicts;
            }
            globalDicts[normalized] = strings;
        }
    }
    function hasLocale(locale) {
        const normalized = toCanonicalLocale(locale) || normalizeLocaleInput(locale);
        if (!normalized)
            return false;
        if (resolveExactLocale(normalized, dictionaries))
            return true;
        return !!resolveShort(getShortPart(normalized));
    }
    async function loadLocale(locale, _loadOptions) {
        if (typeof document === 'undefined')
            return false;
        const normalized = toCanonicalLocale(locale) || normalizeLocaleInput(locale);
        if (!normalized)
            return false;
        if (hasLocale(normalized))
            return true;
        const mapped = shortToCanonical[getShortPart(normalized).toLowerCase()] ?? '';
        const candidates = Array.from(new Set([
            normalizeLocaleInput(locale),
            normalized,
            normalizeLocaleToken(normalized),
            mapped,
            toCanonicalLocale(mapped),
        ])).filter(Boolean);
        const callbackKey = `${globalKey}Callback`;
        for (const candidate of candidates) {
            const callbackRef = rootRef?.[callbackKey];
            if (typeof callbackRef === 'function') {
                try {
                    const result = await Promise.resolve(callbackRef(candidate));
                    if (result && typeof result === 'object') {
                        const directFromMap = result[candidate];
                        if (directFromMap && typeof directFromMap === 'object') {
                            registerLocale(candidate, directFromMap);
                            return true;
                        }
                        registerLocale(candidate, result);
                        return true;
                    }
                }
                catch {
                    // segue para fallback em objeto global
                }
            }
            const external = rootRef?.[globalKey];
            if (external && typeof external === 'object') {
                const existing = resolveExactLocale(candidate, external);
                if (existing && external[existing]) {
                    registerLocale(existing, external[existing]);
                    return true;
                }
            }
        }
        return false;
    }
    function createI18n(runtimeOptions = {}) {
        const autoLanguage = runtimeOptions.autoLanguage !== false;
        const fallbackLanguage = normalizeString(runtimeOptions.language ?? defaultLocale);
        const detectedLanguage = autoLanguage ? getLocaleFromEnvironment() : '';
        const resolvedLanguage = autoLanguage
            ? normalizeLocale(detectedLanguage, fallbackLanguage)
            : normalizeLocale(fallbackLanguage, fallbackLanguage);
        const strings = getStrings(resolvedLanguage);
        function t(key, params, fallback = '') {
            const candidate = getByPath(strings, key);
            const raw = typeof candidate === 'string' ? candidate : fallback || String(key ?? '');
            if (!params)
                return raw;
            return raw.replace(/\{(\w+)\}/g, (_m, tokenKey) => tokenKey in params ? String(params[tokenKey]) : `{${tokenKey}}`);
        }
        return { language: resolvedLanguage, strings, t };
    }
    return {
        normalizeLocale,
        getLocaleFromEnvironment,
        getLocaleFromDocument,
        getStrings,
        registerLocale,
        hasLocale,
        loadLocale,
        createI18n,
    };
}
